import React, { createContext, useContext, useEffect, useState } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase } from '@/integrations/supabase/client';
import { getUserRole } from '@/lib/auth';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  userRole: 'student' | 'company' | null;
  loading: boolean;
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  session: null,
  userRole: null,
  loading: true,
});

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [userRole, setUserRole] = useState<'student' | 'company' | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Set up auth state listener first
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event, session) => {
        setSession(session);
        setUser(session?.user ?? null);

        // Defer role fetching
        if (session?.user) {
          setTimeout(() => {
            getUserRole(session.user.id).then(setUserRole);
          }, 0);
        } else {
          setUserRole(null);
        }
      }
    );

    // Then check for existing session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);

      if (session?.user) {
        getUserRole(session.user.id).then(role => {
          setUserRole(role);
          setLoading(false);
        });
      } else {
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  return (
    <AuthContext.Provider value={{ user, session, userRole, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

import { supabase } from "@/integrations/supabase/client";
import { User, Session } from "@supabase/supabase-js";

export const signUp = async (email: string, password: string, fullName: string, role: 'student' | 'company', additionalData?: any) => {
  const redirectUrl = `${window.location.origin}/`;

  const { data, error } = await supabase.auth.signUp({
    email,
    password,
    options: {
      emailRedirectTo: redirectUrl,
      data: {
        full_name: fullName,
        role: role,
        ...additionalData
      }
    }
  });

  if (error) return { error };
  if (!data.user) return { error: new Error("Failed to create user") };

  // Create user role
  if (data.user) {
    const { error: roleError } = await supabase
      .from('user_roles')
      .insert({ user_id: data.user.id, role });

    if (roleError) {
      console.error("Error creating role:", roleError);
      return { error: roleError };
    }

    // Create student or company profile
    if (role === 'student') {
      const { error: profileError } = await supabase
        .from('student_profiles')
        .insert({
          user_id: data.user.id,
          university: additionalData?.university || null,
          major: additionalData?.major || null
        });

      if (profileError) {
        console.error("Error creating student profile:", profileError);
      }
    } else if (role === 'company') {
      const { error: profileError } = await supabase
        .from('company_profiles')
        .insert({
          user_id: data.user.id,
          company_name: additionalData?.company_name || fullName,
          industry: additionalData?.industry || null
        });

      if (profileError) {
        console.error("Error creating company profile:", profileError);
      }
    }
  }

  return { data, error: null };
};

export const signIn = async (email: string, password: string) => {
  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password,
  });
  return { data, error };
};

export const signOut = async () => {
  const { error } = await supabase.auth.signOut();
  return { error };
};

export const getSession = async (): Promise<{ session: Session | null; user: User | null }> => {
  const { data: { session } } = await supabase.auth.getSession();
  return { session, user: session?.user ?? null };
};

export const getUserRole = async (userId: string): Promise<'student' | 'company' | null> => {
  const { data, error } = await supabase
    .from('user_roles')
    .select('role')
    .eq('user_id', userId)
    .single();

  if (error || !data) return null;
  return data.role as 'student' | 'company';
};

